import{_ as t,o as d,c as l,a3 as o}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"宏参考手册 (Macro Reference)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/macro-system/macro-reference.md","filePath":"user-guide/tools/llm-chat/macro-system/macro-reference.md","lastUpdated":1780654734000}'),a={name:"user-guide/tools/llm-chat/macro-system/macro-reference.md"};function c(i,e,r,n,s,f){return d(),l("div",null,[...e[0]||(e[0]=[o('<div><h1 id="宏参考手册-macro-reference" tabindex="-1">宏参考手册 (Macro Reference) <a class="header-anchor" href="#宏参考手册-macro-reference" aria-label="Permalink to &quot;宏参考手册 (Macro Reference)&quot;">​</a></h1><p>本页面列出了 LLM Chat 中所有可用的内置宏及其详细说明。</p><h2 id="_1-核心上下文宏" tabindex="-1">1. 核心上下文宏 <a class="header-anchor" href="#_1-核心上下文宏" aria-label="Permalink to &quot;1. 核心上下文宏&quot;">​</a></h2><p>用于获取当前会话的基本信息。</p><table tabindex="0"><thead><tr><th style="text-align:left;">宏名称</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>{{user}}</code></td><td style="text-align:left;">当前用户档案的名称</td><td style="text-align:left;"><code>你好，{{user}}</code></td></tr><tr><td style="text-align:left;"><code>{{char}}</code> / <code>{{agent}}</code></td><td style="text-align:left;">当前 Agent 的名称</td><td style="text-align:left;"><code>我是{{char}}</code></td></tr><tr><td style="text-align:left;"><code>{{persona}}</code></td><td style="text-align:left;">当前用户档案的完整描述内容</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><code>{{description}}</code></td><td style="text-align:left;">Agent 的详细描述信息</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><code>{{input}}</code></td><td style="text-align:left;">用户当前输入的内容</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><code>{{lastMessage}}</code></td><td style="text-align:left;">会话中的最后一条消息内容</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><code>{{lastUserMessage}}</code></td><td style="text-align:left;">最后一条用户消息内容</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><code>{{lastCharMessage}}</code></td><td style="text-align:left;">最后一条助手消息内容</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;"><code>{{profileId}}</code></td><td style="text-align:left;">当前使用的 LLM 配置文件 ID</td><td style="text-align:left;">-</td></tr></tbody></table><h2 id="_2-时间与日期宏" tabindex="-1">2. 时间与日期宏 <a class="header-anchor" href="#_2-时间与日期宏" aria-label="Permalink to &quot;2. 时间与日期宏&quot;">​</a></h2><p>所有时间宏都自动感知 Agent 的<a href="./../agents/virtual-timeline">虚拟时间线</a>配置。</p><h3 id="标准格式" tabindex="-1">标准格式 <a class="header-anchor" href="#标准格式" aria-label="Permalink to &quot;标准格式&quot;">​</a></h3><ul><li><code>{{time}}</code>: 12小时制时间 (如 <code>10:30 PM</code>)</li><li><code>{{time24}}</code>: 24小时制时间 (如 <code>22:30</code>)</li><li><code>{{date}}</code>: 英文日期 (如 <code>May 8, 2026</code>)</li><li><code>{{date_ymd}}</code>: ISO 日期 (如 <code>2026-05-08</code>)</li><li><code>{{datetime}}</code>: 完整日期时间 (如 <code>2026-05-08 22:30:00</code>)</li><li><code>{{weekday}}</code>: 英文星期 (如 <code>Friday</code>)</li><li><code>{{isotime}}</code>: ISO 8601 格式时间戳 (如 <code>2026-05-08T14:30:00.000Z</code>)</li><li><code>{{timestamp}}</code>: Unix 时间戳（毫秒）</li></ul><h3 id="中文与本地化格式" tabindex="-1">中文与本地化格式 <a class="header-anchor" href="#中文与本地化格式" aria-label="Permalink to &quot;中文与本地化格式&quot;">​</a></h3><ul><li><code>{{date_cn}}</code>: <code>2026年5月8日</code></li><li><code>{{datetime_cn}}</code>: <code>2026年5月8日 星期五 晚上10点30分</code></li><li><code>{{weekday_cn}}</code>: <code>星期五</code></li><li><code>{{date_jp}}</code>: <code>2025年11月7日（金）</code></li><li><code>{{datetime_jp}}</code>: <code>2025年11月7日（金） 午後10時30分</code></li><li><code>{{date_ko}}</code>: <code>2025년 11월 7일 (금)</code></li><li><code>{{datetime_format::pattern}}</code>: 自定义格式 (如 <code>{{datetime_format::YYYY/MM/DD}}</code>)</li><li><code>{{datetime_locale::ja-JP}}</code>: 日本语本地化格式</li></ul><h3 id="古风格式" tabindex="-1">古风格式 <a class="header-anchor" href="#古风格式" aria-label="Permalink to &quot;古风格式&quot;">​</a></h3><ul><li><code>{{date_cn_ancient}}</code>: 农历/干支 (如 <code>乙巳年（蛇年）十月十八</code>)</li><li><code>{{time_cn_ancient}}</code>: 时辰刻数 (如 <code>亥时一刻</code>)</li><li><code>{{datetime_cn_ancient}}</code>: 完整古风中文日期时间</li><li><code>{{shichen}}</code>: 仅时辰名称 (如 <code>亥时</code>)</li><li><code>{{date_en_ancient}}</code>: 古风英文日期 (如 <code>the 8th day of May, in the year of our Lord 2026</code>)</li><li><code>{{datetime_en_ancient}}</code>: 完整古风英文日期时间</li></ul><h3 id="大写汉字格式" tabindex="-1">大写汉字格式 <a class="header-anchor" href="#大写汉字格式" aria-label="Permalink to &quot;大写汉字格式&quot;">​</a></h3><ul><li><code>{{date_cn_uppercase}}</code>: 大写汉字日期 (如 <code>贰零贰伍年拾贰月肆日</code>)</li><li><code>{{time_cn_uppercase}}</code>: 大写汉字时间 (如 <code>贰拾时叁拾分</code>)</li><li><code>{{datetime_cn_uppercase}}</code>: 完整大写汉字日期时间</li></ul><h2 id="_3-模型元数据宏" tabindex="-1">3. 模型元数据宏 <a class="header-anchor" href="#_3-模型元数据宏" aria-label="Permalink to &quot;3. 模型元数据宏&quot;">​</a></h2><p>获取当前执行请求的模型信息。</p><table tabindex="0"><thead><tr><th style="text-align:left;">宏名称</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>{{modelId}}</code></td><td style="text-align:left;">完整模型 ID</td><td style="text-align:left;"><code>openai:gpt-4o</code></td></tr><tr><td style="text-align:left;"><code>{{modelName}}</code></td><td style="text-align:left;">模型显示名称</td><td style="text-align:left;"><code>GPT-4o</code></td></tr><tr><td style="text-align:left;"><code>{{profileId}}</code></td><td style="text-align:left;">服务配置 ID</td><td style="text-align:left;"><code>my-openai</code></td></tr><tr><td style="text-align:left;"><code>{{profileName}}</code></td><td style="text-align:left;">服务渠道名称</td><td style="text-align:left;"><code>My OpenAI</code></td></tr><tr><td style="text-align:left;"><code>{{provider}}</code></td><td style="text-align:left;">提供商类型</td><td style="text-align:left;"><code>openai</code>, <code>anthropic</code></td></tr></tbody></table><h2 id="_4-功能性宏" tabindex="-1">4. 功能性宏 <a class="header-anchor" href="#_4-功能性宏" aria-label="Permalink to &quot;4. 功能性宏&quot;">​</a></h2><p>提供逻辑处理与文本操作。</p><ul><li><code>{{random::opt1::opt2}}</code>: 随机选择。示例：<code>{{random::高冷::热情::神秘}}</code></li><li><code>{{pick::A::B}}</code>: 基于会话 ID 的稳定选择（同一会话结果始终固定）。</li><li><code>{{roll::NdM}}</code>: 掷骰子。示例：<code>{{roll::1d100}}</code></li><li><code>{{randomInt::min::max}}</code>: 生成指定范围内的随机整数。</li><li><code>{{repeat::text::n}}</code>: 重复文本 N 次。</li><li><code>{{newline}}</code>: 插入一个硬换行符。</li><li><code>{{trim}}</code>: 特殊宏，移除其前后的所有空白和换行（常用于保持模板整洁）。</li></ul><h2 id="_5-变量操作宏" tabindex="-1">5. 变量操作宏 <a class="header-anchor" href="#_5-变量操作宏" aria-label="Permalink to &quot;5. 变量操作宏&quot;">​</a></h2><p>变量允许你在上下文构建过程中传递状态。详见<a href="./session-variables">变量系统详解</a>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">宏名称</th><th style="text-align:left;">说明</th><th style="text-align:left;">阶段</th></tr></thead><tbody><tr><td style="text-align:left;"><code>{{setvar::name::val}}</code></td><td style="text-align:left;">设置临时局部变量</td><td style="text-align:left;">PRE_PROCESS</td></tr><tr><td style="text-align:left;"><code>{{getvar::name}}</code></td><td style="text-align:left;">读取临时局部变量值</td><td style="text-align:left;">SUBSTITUTE</td></tr><tr><td style="text-align:left;"><code>{{incvar::name}}</code></td><td style="text-align:left;">变量自增 1</td><td style="text-align:left;">PRE_PROCESS</td></tr><tr><td style="text-align:left;"><code>{{decvar::name}}</code></td><td style="text-align:left;">变量自减 1</td><td style="text-align:left;">PRE_PROCESS</td></tr><tr><td style="text-align:left;"><code>{{setglobalvar::k::v}}</code></td><td style="text-align:left;">设置全局变量（进程内有效）</td><td style="text-align:left;">PRE_PROCESS</td></tr><tr><td style="text-align:left;"><code>{{getglobalvar::k}}</code></td><td style="text-align:left;">读取全局变量值</td><td style="text-align:left;">SUBSTITUTE</td></tr><tr><td style="text-align:left;"><code>{{incglobalvar::name}}</code></td><td style="text-align:left;">全局变量自增 1</td><td style="text-align:left;">PRE_PROCESS</td></tr><tr><td style="text-align:left;"><code>{{decglobalvar::name}}</code></td><td style="text-align:left;">全局变量自减 1</td><td style="text-align:left;">PRE_PROCESS</td></tr></tbody></table><h2 id="_6-资产与工具宏" tabindex="-1">6. 资产与工具宏 <a class="header-anchor" href="#_6-资产与工具宏" aria-label="Permalink to &quot;6. 资产与工具宏&quot;">​</a></h2><ul><li><code>{{assets::groupId}}</code>: 列出 Agent 的可用资产。可选参数为分组 ID。</li><li><code>{{tools::id1::id2}}</code>: 注入工具定义。支持手动指定工具 ID 列表。</li><li><code>{{tool_usage}}</code>: 注入当前工具调用协议的使用说明（如 VCP 协议）。</li><li><code>{{tool_context}}</code>: 注入已启用工具/插件的实时运行时上下文。支持通过参数指定工具 ID 列表（如 <code>{{tool_context::toolId1::toolId2}}</code>），此时将无视开关状态强制注入。</li><li><code>{{visual_guideline}}</code>: 注入 Agent 配置的视觉化输出指南。</li><li><code>{{cssvar::--name}}</code>: 获取当前主题下 CSS 变量的实际值（如颜色代码）。</li></ul><h2 id="_7-系统信息宏" tabindex="-1">7. 系统信息宏 <a class="header-anchor" href="#_7-系统信息宏" aria-label="Permalink to &quot;7. 系统信息宏&quot;">​</a></h2><p>获取运行环境信息。</p><ul><li><code>{{os}}</code>: 操作系统名称 (如 <code>Windows_NT</code>)</li><li><code>{{osVersion}}</code>: 操作系统版本号 (如 <code>10.0.19045</code>)</li><li><code>{{platform}}</code>: 运行平台 (如 <code>win32</code>)</li><li><code>{{arch}}</code>: CPU 架构 (如 <code>x86_64</code>)</li><li><code>{{hostname}}</code>: 计算机主机名</li><li><code>{{locale}}</code>: 系统语言环境 (如 <code>zh-CN</code>)</li></ul><h2 id="_8-知识库宏" tabindex="-1">8. 知识库宏 <a class="header-anchor" href="#_8-知识库宏" aria-label="Permalink to &quot;8. 知识库宏&quot;">​</a></h2><p>提供知识库检索注入能力。详见<a href="./../knowledge-base-integration">知识库集成</a>。</p><ul><li><code>{{kb}}</code>: 触发知识库检索并注入结果。无参数时检索所有已启用的关联知识库；可指定知识库名称和召回上限（如 <code>{{kb::我的知识库::5}}</code>）。</li><li><code>{{kb_list}}</code>: 列出当前 Agent 关联的知识库信息（供 LLM 感知可用知识源）。</li></ul></div>',1)])])}const x=t(a,[["render",c]]);export{g as __pageData,x as default};
